using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;

    public RecipeService()
    {
        _recipes = SeedRecipes();
    }

    public List<RecipeCategory> GetCategories() =>
    [
        new() { Name = "Breakfast", Icon = "🥞", Description = "Start your morning right" },
        new() { Name = "Lunch", Icon = "🥗", Description = "Midday meals and salads" },
        new() { Name = "Dinner", Icon = "🍝", Description = "Hearty evening dishes" },
        new() { Name = "Desserts", Icon = "🍰", Description = "Sweet treats and bakes" },
        new() { Name = "Snacks", Icon = "🥨", Description = "Quick bites and appetizers" },
        new() { Name = "Drinks", Icon = "🥤", Description = "Beverages and smoothies" },
    ];

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    private static List<Recipe> SeedRecipes() =>
    [
        new()
        {
            Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
            Description = "Fluffy golden pancakes perfect for a lazy weekend morning.",
            Ingredients = ["2 cups flour", "2 eggs", "1½ cups milk", "3 tbsp sugar", "2 tsp baking powder", "Pinch of salt", "Butter for cooking"],
            Steps = ["Mix dry ingredients in a bowl.", "Whisk eggs and milk together, then combine with dry mix.", "Heat a buttered pan over medium heat.", "Pour ¼ cup batter per pancake and cook until bubbles form.", "Flip and cook until golden brown.", "Serve with maple syrup and fresh berries."],
            TotalRatings = 12, RatingSum = 50
        },
        new()
        {
            Id = 2, Title = "Avocado Toast", Category = "Breakfast",
            Description = "Simple, healthy, and endlessly customizable.",
            Ingredients = ["2 slices sourdough bread", "1 ripe avocado", "Lemon juice", "Red pepper flakes", "Salt and pepper", "Optional: poached egg"],
            Steps = ["Toast the bread until golden.", "Mash avocado with lemon juice, salt, and pepper.", "Spread onto toast.", "Top with red pepper flakes and optional poached egg."],
            TotalRatings = 8, RatingSum = 35
        },
        new()
        {
            Id = 3, Title = "Caesar Salad", Category = "Lunch",
            Description = "A crisp, tangy classic with homemade dressing.",
            Ingredients = ["1 head romaine lettuce", "½ cup croutons", "¼ cup parmesan cheese", "Caesar dressing", "Grilled chicken (optional)"],
            Steps = ["Wash and chop the romaine lettuce.", "Toss with Caesar dressing.", "Top with croutons, shaved parmesan, and grilled chicken."],
            TotalRatings = 6, RatingSum = 25
        },
        new()
        {
            Id = 4, Title = "Spaghetti Bolognese", Category = "Dinner",
            Description = "A rich, slow-simmered meat sauce over al dente pasta.",
            Ingredients = ["400g spaghetti", "500g ground beef", "1 onion, diced", "2 cloves garlic", "400g crushed tomatoes", "2 tbsp tomato paste", "1 tsp oregano", "Salt and pepper", "Parmesan for serving"],
            Steps = ["Cook spaghetti according to package directions.", "Brown ground beef with onion and garlic.", "Add crushed tomatoes, tomato paste, and oregano.", "Simmer for 20 minutes, stirring occasionally.", "Season with salt and pepper.", "Serve sauce over pasta with parmesan."],
            TotalRatings = 15, RatingSum = 68
        },
        new()
        {
            Id = 5, Title = "Chocolate Chip Cookies", Category = "Desserts",
            Description = "Chewy, gooey cookies with pools of melted chocolate.",
            Ingredients = ["2¼ cups flour", "1 cup butter, softened", "¾ cup sugar", "¾ cup brown sugar", "2 eggs", "1 tsp vanilla", "1 tsp baking soda", "2 cups chocolate chips"],
            Steps = ["Preheat oven to 375°F (190°C).", "Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour and baking soda.", "Fold in chocolate chips.", "Drop spoonfuls onto a baking sheet.", "Bake 9-11 minutes until edges are golden."],
            TotalRatings = 20, RatingSum = 95
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Snacks",
            Description = "Fresh, zesty guacamole ready in minutes.",
            Ingredients = ["3 ripe avocados", "1 lime, juiced", "½ onion, diced", "1 tomato, diced", "Fresh cilantro", "Salt", "Jalapeño (optional)"],
            Steps = ["Mash avocados in a bowl.", "Stir in lime juice, onion, tomato, and cilantro.", "Season with salt and jalapeño to taste.", "Serve immediately with tortilla chips."],
            TotalRatings = 10, RatingSum = 42
        },
        new()
        {
            Id = 7, Title = "Mango Smoothie", Category = "Drinks",
            Description = "A tropical, creamy smoothie bursting with flavor.",
            Ingredients = ["1 cup frozen mango chunks", "1 banana", "½ cup yogurt", "½ cup orange juice", "Honey to taste"],
            Steps = ["Add all ingredients to a blender.", "Blend until smooth.", "Pour into a glass and enjoy."],
            TotalRatings = 7, RatingSum = 30
        },
        new()
        {
            Id = 8, Title = "Grilled Chicken Wrap", Category = "Lunch",
            Description = "A protein-packed wrap with fresh veggies.",
            Ingredients = ["2 flour tortillas", "1 grilled chicken breast, sliced", "Lettuce", "Tomato slices", "Ranch dressing", "Shredded cheese"],
            Steps = ["Lay out tortillas and spread ranch dressing.", "Layer chicken, lettuce, tomato, and cheese.", "Roll up tightly, tucking in the sides.", "Slice in half and serve."],
            TotalRatings = 5, RatingSum = 22
        },
    ];
}
CSHARP

