@rendermode InteractiveServer

<div class="star-rating">
    <span class="rating-label">Rate this recipe:</span>
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= (_userRating ?? 0) ? "filled" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => _hover = star"
                  @onmouseout="() => _hover = 0"
                  role="button"
                  title="@star star(s)">
                @(star <= (_hover > 0 ? _hover : (_userRating ?? 0)) ? "★" : "☆")
            </span>
        }
    </div>
    @if (_userRating.HasValue)
    {
        <span class="rating-thanks">Thanks! You rated @_userRating stars.</span>
    }
    @if (AverageRating > 0)
    {
        <span class="rating-avg">Community average: @AverageRating.ToString("0.0") / 5 (@TotalRatings ratings)</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }
    [Parameter] public EventCallback<int> OnRate { get; set; }

    private int? _userRating;
    private int _hover;

    private async Task SubmitRating(int stars)
    {
        _userRating = stars;
        await OnRate.InvokeAsync(stars);
    }
}
