@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@_model.Title" has been added.
        <a href="/recipe/@_submittedId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" class="recipe-form">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat.Name">@cat.Name</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Short Description</label>
            <InputTextArea id="description" @bind-Value="_model.Description" class="form-control" rows="2" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_ingredientsText" class="form-control" rows="5"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_stepsText" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;..." />
        </div>

        <button type="submit" class="btn btn-primary"
                disabled="@(string.IsNullOrWhiteSpace(_model.Title) || string.IsNullOrWhiteSpace(_model.Category))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private Recipe _model = new();
    private string _ingredientsText = string.Empty;
    private string _stepsText = string.Empty;
    private bool _submitted;
    private int _submittedId;

    private void HandleSubmit()
    {
        _model.Ingredients = _ingredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();
        _model.Steps = _stepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        RecipeService.AddRecipe(_model);
        _submittedId = _model.Id;
        _submitted = true;
    }
}
