cat >> /tmp/sv-67654c8da0e044de9ad2859fbebccec2/RecipeCommunity/wwwroot/app.css << 'CSS'

/* Recipe Community styles */
.hero {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border-radius: 1rem;
}

.category-card {
    transition: transform 0.2s, box-shadow 0.2s;
    cursor: pointer;
}

.category-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 4px 15px rgba(0,0,0,0.15);
}

.category-icon {
    font-size: 3rem;
    display: block;
}

.star-rating {
    padding: 1rem 0;
}

.star-rating .stars {
    display: inline-flex;
    gap: 0.25rem;
}

.star-rating .star {
    font-size: 2rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.15s;
    user-select: none;
}

.star-rating .star:hover,
.star-rating .star.filled {
    color: #f5a623;
}

.rating-label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.rating-thanks {
    display: block;
    color: #28a745;
    margin-top: 0.5rem;
}

.rating-avg {
    display: block;
    color: #6c757d;
    font-size: 0.9rem;
    margin-top: 0.25rem;
}

.recipe-steps li {
    line-height: 1.8;
}

.recipe-form {
    max-width: 700px;
}
CSS

